1	type Item = {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	};
7	type Customer = { yearsWithMHPCO: number };
8	type Step = { op: "quote"; items: Item[] };
9	type Scenario = {
10	  customer: Customer;
11	  steps: Step[];
12	};
13	
14	const PROCESSING_FEE = 5;
15	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
16	const CURSE_SURCHARGE_RATE = 0.5;
17	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
18	const HIGH_ENCHANTMENT_THRESHOLD = 5;
19	const LOYALTY_DISCOUNT_RATE = 0.2;
20	const LOYALTY_THRESHOLD_YEARS = 2;
21	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
22	const ITEM_BASE: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	  moonstone: 25,
29	};
30	
31	const COMPONENT_BLOCK_SIZE = 3;
32	const COMPONENT_BLOCK_BASE = 60;
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	
35	const groupCountsByType = (items: Item[]): Map<string, number> => {
36	  const counts = new Map<string, number>();
37	  for (const item of items) {
38	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
39	  }
40	  return counts;
41	};
42	
43	const baseForGroup = (type: string, count: number): number => {
44	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
45	    return COMPONENT_BLOCK_BASE;
46	  }
47	  return count * ITEM_BASE[type];
48	};
49	
50	const calculatePolicyBase = (items: Item[]): number => {
51	  let total = 0;
52	  for (const [type, count] of groupCountsByType(items)) {
53	    total += baseForGroup(type, count);
54	  }
55	  return total;
56	};
57	
58	const roundUpInMHPCOsFavor = (amount: number): number => Math.ceil(amount);
59	
60	type ItemSurcharge = { applies: (item: Item) => boolean; rate: number };
61	
62	const ITEM_SURCHARGES: ItemSurcharge[] = [
63	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
64	  {
65	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
66	    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
67	  },
68	];
69	
70	const surchargesForItem = (item: Item): number =>
71	  ITEM_SURCHARGES.reduce(
72	    (sum, { applies, rate }) => sum + (applies(item) ? ITEM_BASE[item.type] * rate : 0),
73	    0,
74	  );
75	
76	const itemSpecificSurcharges = (items: Item[]): number =>
77	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
78	
79	type PolicyContext = { customer: Customer; quoteIndex: number };
80	
81	type PolicyModifier = {
82	  applies: (context: PolicyContext) => boolean;
83	  signedRate: number;
84	};
85	
86	const POLICY_MODIFIERS: PolicyModifier[] = [
87	  { applies: () => true, signedRate: +FIRST_CONTRACT_SURCHARGE_RATE },
88	  {
89	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
90	    signedRate: -LOYALTY_DISCOUNT_RATE,
91	  },
92	  {
93	    applies: ({ quoteIndex }) => quoteIndex > 0,
94	    signedRate: -FOLLOW_UP_DISCOUNT_RATE,
95	  },
96	];
97	
98	const policyWideAdjustment = (policyBase: number, context: PolicyContext): number =>
99	  POLICY_MODIFIERS.reduce(
100	    (sum, { applies, signedRate }) => sum + (applies(context) ? policyBase * signedRate : 0),
101	    0,
102	  );
103	
104	const quotePremium = ({ items }: Step, context: PolicyContext): number => {
105	  const policyBase = calculatePolicyBase(items);
106	  return roundUpInMHPCOsFavor(
107	    policyBase +
108	      itemSpecificSurcharges(items) +
109	      policyWideAdjustment(policyBase, context) +
110	      PROCESSING_FEE,
111	  );
112	};
113	
114	export const runScenario = ({ customer, steps }: Scenario): { results: unknown[] } => {
115	  let quoteIndex = 0;
116	  const results = steps.map((step) => {
117	    const result = { premium: quotePremium(step, { customer, quoteIndex }) };
118	    quoteIndex += 1;
119	    return result;
120	  });
121	  return { results };
122	};
